#include<bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) meke_pair(x,y);
#define inf 0x3f3f3f3f
using namespace std;
inline int read(){
    int x=0,f=1;
    char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
    while(ch>='0'&&ch<='9')x=x*10+ch-'0',ch=getchar();
    return x*f;
}
void write(int x){
    if(x<0)putchar('-'),x=-x;
    if(x>9)write(x/10);
    putchar(x%10+'0');return;
}
CI MAXN=1e4+5;
int n,s,a,b,answer=0;
pair<int,int> Apple[MAXN];
bool cmp_in_pair(pair<int,int> x,pair<int,int> y)
{
    return x.second<y.second;
}
int main(void)
{
    n=read(),s=read(),a=read(),b=read();
    for(int i=1;i<=n;++i)Apple[i].first=read(),Apple[i].second=read();
    sort(Apple+1,Apple+1+n,cmp_in_pair);
    for(int i=1;i<=n;++i)
    {
        if(s-Apple[i].second<0)
        {
            break;
        }
        if(Apple[i].first>a+b)
        {
            continue;
        }
        else
        {
            s-=Apple[i].second;
            ++answer;
        }
    }
    write(answer);
    return false;
}
